<template><div class="full-chain-page"><section class="hero-band"><div class="hero-copy"><p class="eyebrow">Learning Multi-Agent Workbench</p><h2>Personalized Learning Closed Loop</h2><p class="hero-summary">From learning profiling to resource generation - a complete AI-powered learning pipeline.</p></div><div class="readiness-card"><span>Readiness</span><strong>86%</strong></div></section><section class="profile-strip"><div class="profile-item"><span>Student</span><strong>Yu</strong></div><div class="profile-item"><span>Region</span><strong>Shanghai</strong></div><div class="profile-item"><span>Direction</span><strong>AI Basics</strong></div><div class="profile-item"><span>Skills</span><strong>Python / SQL / AI</strong></div></section><section class="status-overview"><article v-for="s in statusItems" :key="s.title"><span>{{s.status}}</span><h3>{{s.title}}</h3><p>{{s.desc}}</p></article></section><section class="usage-guide"><h3>Learning Flow</h3><div v-for="(step,i) in usageGuide" :key="i"><strong>{{step.step}}</strong><h4>{{step.title}}</h4><p>{{step.desc}}</p></div></section><section class="agent-cards"><h3>Core Agents</h3><div v-for="a in agents" :key="a.name" class="agent-card"><strong>{{a.name}}</strong><p>{{a.desc}}</p></div></section><section class="platform-section"><h3>AI Capability Status</h3><p>{{aiStatusBadge}}</p><div v-for="c in aiCapabilities" :key="c.name"><span :class="c.configured?'ok':'warn'">{{c.status}}</span>{{c.name}}</div></section></div></template><script>import axios from 'axios';import aiCourseKnowledgeBase from '../data/aiCourseKnowledgeBase';export default{name:'FullChain',data(){return{readinessScore:86,userName:'Yu',province:'Shanghai',targetDirection:'AI Basics',skillTags:['Python','SQL','AI'],statusItems:[{status:'Done',title:'Portal & Demo Link',desc:'Login, navigation, demo data form a closed loop.'},{status:'Connected',title:'Profile/Quiz/Tutor',desc:'Reuse existing pages for 3-mode learning closed loop.'},{status:'Configuring',title:'iFLYTEK API Config',desc:'Spark, Doc Understanding, PPT, Security - configured via env vars.'},{status:'Pending',title:'Learning Agent API',desc:'Unified agent interface for profiling, resource gen, evaluation.'}],usageGuide:[{step:'01',title:'Register & Select Direction',desc:'Register and choose AI, Python, ML, CS, or Mechanical direction.'},{step:'02',title:'Study in Resource Reading',desc:'Read textbooks, record pages, mark key points, write notes.'},{step:'03',title:'Sync to Knowledge Quiz',desc:'System converts reading progress into personalized questions.'},{step:'04',title:'1-on-1 AI Tutoring',desc:'AI teacher asks questions based on material, you answer by voice.'},{step:'05',title:'Refresh Learning Profile',desc:'Profile shows reading volume, quiz results, weak areas.'}],agents:[{name:'Portrait Agent',desc:'Extracts student profile from natural language.'},{name:'Path Agent',desc:'Recommends learning steps and resource order.'},{name:'Training Agent',desc:'Organizes questions, follow-ups, and evaluation in 1-on-1 tutoring.'},{name:'Evaluation Agent',desc:'Converts training results into learning diagnosis.'},{name:'Resource Agent',desc:'Maps knowledge gaps to documents, diagrams, quizzes, and PPTs.'}],aiCapabilities:[{name:'Spark Agent',status:'Detecting',configured:false},{name:'Voice TTS/IAT',status:'Detecting',configured:false},{name:'PPT Generation',status:'Detecting',configured:false},{name:'Image Generation',status:'Detecting',configured:false}],aiStatusBadge:'0/4 AI capabilities configured',agentStatus:'Local Demo Mode'}},mounted(){this.loadAiCapabilityStatus()},methods:{async loadAiCapabilityStatus(){const checks=[{name:'Spark Agent',url:'/api/learning-agent/status',flag:'sparkConfigured'},{name:'Voice TTS/IAT',url:'/api/voice/status',flag:'configured'},{name:'PPT Generation',url:'/api/ppt/status',flag:'configured'},{name:'Image Generation',url:'/api/image/status',flag:'configured'}];const results=await Promise.all(checks.map(async c=>{try{const r=await axios.get(c.url,{timeout:5000});return{name:c.name,status:r.data&&r.data[c.flag]?'Configured':'Not configured',configured:!!(r.data&&r.data[c.flag]),mode:r.data&&r.data.mode}}catch(e){return{name:c.name,status:'Unavailable',configured:false,mode:'unavailable'}}}));this.aiCapabilities=results;const n=results.filter(r=>r.configured).length;this.aiStatusBadge=n+'/'+results.length+' AI capabilities configured';this.agentStatus=n>0?'Partially connected':'Local demo mode'}}}}</script>